import numpy as np
from numba import jit

@jit(nopython=True)
def priority(available_time, process_time):
    return available_time + process_time + 0.5 * process_time / (available_time + 1)

def select_machine(machine_process_times, machine_available_time):
    if len(machine_process_times) == 0:
        machine_id = 0
        return machine_id

    best_score = np.inf
    machine_id = 0
    for m_id, p_time in machine_process_times:
        avail = machine_available_time[m_id]
        score = priority(avail, p_time)
        if score < best_score:
            best_score = score
            machine_id = m_id

    return machine_id

import numpy as np
from numba import jit

@jit(nopython=True)
def priority(start, proc, mean_load):
    return start + proc + 0.5 * abs((start + proc) - mean_load)

def select_machine(machine_process_times, machine_available_time):
    if not machine_process_times:
        return 0
    loads = np.zeros(len(machine_available_time), dtype=np.int64)
    for mid, start in enumerate(machine_available_time):
        loads[mid] = start
    mean_load = np.mean(loads)
    min_priority = float('inf')
    machine_id = 0
    for mid, proc in machine_process_times:
        start = machine_available_time[mid]
        prio = priority(start, proc, mean_load)
        if prio < min_priority:
            min_priority = prio
            machine_id = mid
    return machine_id
